// Telegram uses a simple token match, not HMAC — per Telegram Bot API spec (R-02: fail-closed)
const secret = $env['TELEGRAM_WEBHOOK_SECRET'] ?? '';
const sig = $input.first().headers['x-telegram-bot-api-secret-token'] ?? '';
if (!secret || !sig || sig !== secret) {
  throw new Error('Webhook token invalid — dropping payload (R-02)');
}

const body = $input.first().json;
const message = body?.message ?? body?.edited_message;
if (!message?.text) throw new Error('No text in Telegram update');

return [{
  json: {
    intent: message.text,
    chat_id: String(message.chat.id),
    user_id: String(message.from?.id ?? ''),
    timestamp: new Date().toISOString(),
    metadata: { message_id: message.message_id }
  }
}];

// HMAC-SHA256 over the exact body string the Router will read.
// Body must be built explicitly here so n8n's HTTP node does not re-serialize
// and break signature validation (raw bytes must match).
const crypto = require('crypto');
const p = $input.first().json;
const bodyObj = {
  intent: p.intent,
  chat_id: p.chat_id,
  user_id: p.user_id,
  timestamp: p.timestamp,
  metadata: p.metadata,
};
const bodyStr = JSON.stringify(bodyObj);
const secret = $env['SKILLS_ROUTER_SECRET'] ?? '';
if (!secret) throw new Error('SKILLS_ROUTER_SECRET missing — fail-closed (R-02)');
const sig = 'sha256=' + crypto.createHmac('sha256', secret).update(bodyStr).digest('hex');
return [{ json: { _bodyStr: bodyStr, _sig: sig } }];
